var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"MN No. SFMC002M000622-01\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n보안적법성 회의록","JPN":"MN No. SFMC002M000622-01\\n<color=#ffd34c>1級要因</color> 閲覧承認資料\\n保安適法性議事録","ENG":"MN No. SFMC002M000622-01\\n<color=#ffd34c>Class 1 Person of Interest</color> Viewing Approval Documents\\nSecurity Legality Meeting Minutes","TWN":"(TWN)MN No. SFMC002M000622-01\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n보안적법성 회의록"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그럼 이 여자도 결국 Type-C 구상안이 목적이란 건가.","JPN":"それではこの女も結局Type-C構想中が目的という濃いか。","ENG":"So this woman too is ultimately after the Type-C draft proposal, is that it?","TWN":"(TWN)그럼 이 여자도 결국 Type-C 구상안이 목적이란 건가."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이상하군. 위험한 일에서는 발을 뺄 사람 같았는데.","JPN":"変であるね。危ない事では足を除く人のようだったが。","ENG":"Strange. She seemed like the type to pull out of dangerous business.","TWN":"(TWN)이상하군. 위험한 일에서는 발을 뺄 사람 같았는데."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"꽤 예전부터 관련이 있었던 것 같더군요.","JPN":"かなりこの前から関連があったようですね。","ENG":"It seems she's been involved for quite some time.","TWN":"(TWN)꽤 예전부터 관련이 있었던 것 같더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"예전부터?","JPN":"この前から?","ENG":"Since when?","TWN":"(TWN)예전부터?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. <color=#ff3636>[DATA EXPUNGED]</color>에 대해 조사하던 중 흥미로운 자료를 입수했습니다.","JPN":"はい。<color=#ff3636>[DATA EXPUNGED]</color>について調査した中おもしろい資料を手に入れました。","ENG":"Yes. While investigating <color=#ff3636>[DATA EXPUNGED]</color>, we obtained some interesting materials.","TWN":"(TWN)네. <color=#ff3636>[DATA EXPUNGED]</color>에 대해 조사하던 중 흥미로운 자료를 입수했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>[DATA EXPUNGED]</color>의 혈육이 연구소에서 가깝게 지낸 여성의 용모가 제인 도우와 흡사합니다.","JPN":"<color=#ff3636>[DATA EXPUNGED]</color>の血肉が研究所で近く過ごした女性の容姿がジェーン・ドウとそっくりです。","ENG":"A woman who spent time near the research facility where <color=#ff3636>[DATA EXPUNGED]</color>'s blood was stored bears a close resemblance to Jane Doe.","TWN":"(TWN)<color=#ff3636>[DATA EXPUNGED]</color>의 혈육이 연구소에서 가깝게 지낸 여성의 용모가 제인 도우와 흡사합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래? 증인이라도 찾은 건가?","JPN":"そう?証人でも探すのか?","ENG":"Really? Did you find a witness or something?","TWN":"(TWN)그래? 증인이라도 찾은 건가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아뇨. ■■한 관계자의 소지품을 조사하던 중 해당 인물이 촬영된 단체 사진을 발견했습니다. ","JPN":"いいえ。■■一関係者の所持品を調査した中該当人物が撮影された団体写真を見つけました。","ENG":"No. While investigating the personal effects of a certain official, we discovered a group photograph containing this individual.","TWN":"(TWN)아뇨. ■■한 관계자의 소지품을 조사하던 중 해당 인물이 촬영된 단체 사진을 발견했습니다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이후 다른 관계자를 수소문해 봤지만, 대다수가 사망하거나 종적을 감춘 상태였습니다.","JPN":"以後他の関係者をうわさをたよりに探してみたが、大多数が死亡するとか足跡を隠した状態でした。","ENG":"We subsequently tried to locate other related individuals, but the majority were either deceased or had gone into hiding.","TWN":"(TWN)이후 다른 관계자를 수소문해 봤지만, 대다수가 사망하거나 종적을 감춘 상태였습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"대부분 석연치 않은 이유로 말이죠. 교통사고라거나.","JPN":"大部分釈然としない理由で言葉ですよ。交通事故とか。","ENG":"Mostly under dubious circumstances. Traffic accidents, for instance.","TWN":"(TWN)대부분 석연치 않은 이유로 말이죠. 교통사고라거나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"대처가 한 발 늦었군.","JPN":"対処が一発遅れたな。","ENG":"Our response was one step behind.","TWN":"(TWN)대처가 한 발 늦었군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"연관성을 증명할 다른 증거품은 없나?","JPN":"関連性を証明する他の証拠品はないか?","ENG":"No other evidence to prove the connection?","TWN":"(TWN)연관성을 증명할 다른 증거품은 없나?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"없었습니다. 확보에 성공한 사진도 소유자가 중고로 매매한 가구에서 발견됐습니다.","JPN":"なかったです。確保に成功した写真も所有者が中古で売買した家具で発見されました。","ENG":"None. Even the photo we secured was discovered in second-hand furniture that the owner had sold.","TWN":"(TWN)없었습니다. 확보에 성공한 사진도 소유자가 중고로 매매한 가구에서 발견됐습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"구매자는 70대 여성으로, 사진을 주인에게 돌려주려고 했지만 연락이 되지 않아 보관 중이었다고 합니다.","JPN":"購入者は７０代女性で、写真を主人に返そうとしたが連絡にならなくて保管中だったとします。","ENG":"The purchaser was a woman in her 70s who says she tried to return the photo to its owner but couldn't make contact, so she kept it in storage.","TWN":"(TWN)구매자는 70대 여성으로, 사진을 주인에게 돌려주려고 했지만 연락이 되지 않아 보관 중이었다고 합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"연구원으로 위장 잠입해서 정보를 빼내려고 했을지도 모르죠.","JPN":"研究員で偽装しのび込んで情報を抜き取ろうとしたかも知れないでしょう。","ENG":"She may have been trying to extract information through infiltration disguised as a researcher.","TWN":"(TWN)연구원으로 위장 잠입해서 정보를 빼내려고 했을지도 모르죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"가능성은 배제할 수 없겠지.","JPN":"可能性は排除することができないだろう。","ENG":"We can't rule out that possibility.","TWN":"(TWN)가능성은 배제할 수 없겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"개입하실 겁니까?","JPN":"介入するのですか?","ENG":"Will you intervene?","TWN":"(TWN)개입하실 겁니까?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"내 개입은 한동안 자네가 마지막일 걸세.","JPN":"私の介入はしばらくの間君が最後の仕事濃にしよう。","ENG":"You shall be the last to see me intervene for some time.","TWN":"(TWN)내 개입은 한동안 자네가 마지막일 걸세."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이 이상 설쳐 봐야 소란만 커져.","JPN":"この以上のさばってみてこそ騒乱だけ大きくなる。","ENG":"Any further digging will only increase the commotion.","TWN":"(TWN)이 이상 설쳐 봐야 소란만 커져."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"마다해 주셔서 다행이네요. 요새 일어나는 소란만으로도 정신이 없거든요.","JPN":"厭ってくれて幸いですね。この頃起きる騒乱だけでも忙しいんですよ。","ENG":"I'm relieved you declined. We're already overwhelmed by the commotion lately.","TWN":"(TWN)마다해 주셔서 다행이네요. 요새 일어나는 소란만으로도 정신이 없거든요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"보고는 이상입니다. 지시하실 사항이 있으신가요?","JPN":"報告は以上です。指示する事項があるのでしょうか?","ENG":"That concludes my report. Do you have any instructions?","TWN":"(TWN)보고는 이상입니다. 지시하실 사항이 있으신가요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"정보부 규모를 지금보다 확장하고 싶군.","JPN":"情報部規模を今より拡張したいね。","ENG":"I wish to expand the Intelligence Department beyond its current scale.","TWN":"(TWN)정보부 규모를 지금보다 확장하고 싶군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"현 예산 내에서라면 최대 15%까지 가능합니다.\\n개편안을 준비해 드릴까요?","JPN":"現予算内でなら最大15%まで可能です。\\n改編案を準備して差し上げましょうか?","ENG":"We can manage up to 15% within the current budget.\\nShall I prepare a reorganization plan?","TWN":"(TWN)현 예산 내에서라면 최대 15%까지 가능합니다.\\n개편안을 준비해 드릴까요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아니, 자네에게 일임하지. 10% 선에서 추진해 보게.","JPN":"いや、君に一任する。10%線で推進してみなさい。","ENG":"No, I'll leave it to you. Proceed within the 10% margin.","TWN":"(TWN)아니, 자네에게 일임하지. 10% 선에서 추진해 보게."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"알겠습니다. 그럼 다음에 다시 뵙도록 하죠.","JPN":"わかりました。それでは次にまたお目にかかるようにします。","ENG":"Understood. Then I shall see you again next time.","TWN":"(TWN)알겠습니다. 그럼 다음에 다시 뵙도록 하죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};